section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/agency-discovery-call-scorecard.json",
  "title": "Agency Discovery Call Scorecard rubric",
  "type": "object",
  "required": [
    "slug",
    "axes",
    "score_range",
    "decision_threshold",
    "owner"
  ],
  "properties": {
    "slug": {
      "type": "string",
      "const": "agency-discovery-call-scorecard"
    },
    "axes": {
      "type": "array",
      "minItems": 3,
      "items": {
        "type": "object",
        "required": [
          "name",
          "weight",
          "anchors"
        ],
        "properties": {
          "name": {
            "type": "string"
          },
          "weight": {
            "type": "number",
            "minimum": 0,
            "maximum": 1
          },
          "anchors": {
            "type": "array",
            "minItems": 2,
            "items": {
              "type": "string"
            }
          }
        },
        "additionalProperties": false
      }
    },
    "score_range": {
      "type": "array",
      "minItems": 2,
      "maxItems": 2,
      "items": {
        "type": "number"
      }
    },
    "decision_threshold": {
      "type": "number"
    },
    "owner": {
      "type": "string"
    }
  },
  "additionalProperties": false
}
